import os

def delete_file(filename):
    # Resolve absolute path of the file
    abs_path = os.path.abspath(filename)
    
    # Verify that the file path starts with the allowed directory
    if not abs_path.startswith('/uploads'):
        raise ValueError('Invalid file path')
    
    # Delete the file
    os.remove(abs_path)